arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9: HasIndex now throws for Cosmos entities — remove it.
    // Cosmos indexing is managed via the container's indexing policy.

    // EF Core 9: Default discriminator property renamed from "Discriminator" to "$type".
    // Preserve old name so existing documents remain readable.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // EF Core 9: id no longer includes discriminator (was "Blog|1", now just "1").
    // Preserve old compound format so existing documents are still found by key.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

